data.output:
	})
}

// Reopen sets a bead's status back to open, clears claim fields, optionally
// appends notes, and records an immutable reopen event — all in one atomic
// lock acquisition.
func (s *Store) Reopen(id string, reason string, appendNotes string) error {
	now := time.Now().UTC()
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}
		found := false
		for i := range beads {
			if beads[i].ID != id {
				continue
			}
			b := &beads[i]
			if err := transitionLifecycleInPlace(b, StatusOpen, LifecycleTransitionOptions{
				ManualReopen: true,
			}); err != nil {
				return err
			}
			b.Owner = ""
			b.UpdatedAt = now
			if b.Extra == nil {
				b.Extra = make(map[string]any)
			}
			// Clear claim fields
			clearClaimExtraKeys(b.Extra)
			// Append notes
			if appendNotes != "" {
				if b.Notes != "" {
					b.Notes = b.Notes + "\n\n" + appendNotes
				} else {
					b.Notes = appendNotes
				}
			}
			// Record reopen event. If events were externalized at close,
			// pull them back inline so the active row carries the full
			// history again and the attachment ref is dropped.
			if hasEventsAttachment(b) {
				if err := s.inlineEventsInPlace(b); err != nil {
					return err
				}
				_ = os.Remove(s.eventsAttachmentPath(b.ID))
			}
			var events []BeadEvent
			if raw, ok := b.Extra["events"]; ok {
				events = decodeBeadEvents(raw)
			}
			// Detect last review verdict before appending the reopen event so
			// we can identify APPROVE verdicts contradicted by the operator.
			verdictWas := lastReviewVerdictFromEvents(events)
			evt := BeadEvent{
				Kind:      "reopen",
				CreatedAt: now,
			}
			if reason != "" {
				evt.Summary = reason
			}
			events = append(events, evt)
			// Emit accuracy override when operator reopens an APPROVE-reviewed
			// bead (potential false-negative — reviewer approved fake work).
			if verdictWas == "APPROVE" {
				body := "verdict_was=APPROVE\noperator_action=reopen"
				if reason != "" {
					body += "\nreason=" + reason
				}
				events = append(events, BeadEvent{
					Kind:      "review-accuracy-override",
					Summary:   "APPROVE verdict contradicted by operator reopen",
					Body:      body,
					Source:    "Store.Reopen",
					CreatedAt: now,
				})
			}
			encoded := make([]map[string]any, 0, len(events))
			for _, e := range events {
				encoded = append(encoded, map[string]any{
					"kind":       e.Kind,
					"summary":    e.Summary,
					"body":       e.Body,
					"actor":      e.Actor,
					"created_at": e.CreatedAt,
					"source":     e.Source,
				})
			}
			b.Extra["events"] = encoded
			if err := s.validateBead(b); err != nil {
				return err
			}
			if err := s.runHook("validate-bead-update", b); err != nil {
				return err
			}

	}
	cmd.Flags().String("session", "", "Agent session ID that completed this bead")
	cmd.Flags().String("commit", "", "Closing commit SHA (auto-detected if not provided)")
	return cmd
}

func (f *CommandFactory) newBeadReopenCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "reopen <id>",
		Short: "Reopen a closed bead",
		Long: `Reopen a closed or stalled bead.

Atomically sets status to open, clears claim fields, optionally appends
		notes, and records a reopen event in the bead's event log.`,
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			if err := f.checkLifecycleMigrationGate(cmd); err != nil {
				return err
			}
			s := f.beadStore()
			reason, _ := cmd.Flags().GetString("reason")
			appendNotes, _ := cmd.Flags().GetString("append-notes")
			return f.withBeadTrackerWriteLock(func() error {
				if err := s.Reopen(args[0], reason, appendNotes); err != nil {
					return err
				}
				if _, err := f.beadAutoCommit("reopen " + args[0]); err != nil {
					return err
				}
				return nil
			})
		},
	}
	cmd.Flags().String("reason", "", "Reason for reopening (recorded as event summary)")
	cmd.Flags().String("append-notes", "", "Text to append to the bead's notes field")
	return cmd
}

